// // This module selects between two 5-bit input signals, dout0 and dout1, based on the value of the control signal node. When node is low (0), the output dout reflects din1; when node is high (1), dout reflects din0.
module top_module(din0, din1, node, dout);input [4:0]din0;
    input [4:0]din1;
    input node;
    output wire[4:0] dout;

    assign dout = node?din1:din0;endmodule
